use std::os::raw::{c_char, c_int};

#[repr(C)]
struct Point {
    x: c_int,
    y: c_int,
}

extern "C" fn add_point(p1: *const Point, p2: *const Point) -> Point {
    let p1 = unsafe { &*p1 };
    let p2 = unsafe { &*p2 };
    Point { x: p1.x + p2.x, y: p1.y + p2.y }
}

fn main() {}

