fixed_code:
use std::os::raw::c_int;

#[repr(C)]
struct Nested {
    inner: i32,
}

#[repr(C)]
struct Outer {
    nested: *mut Nested,
}

extern "C" {
    fn process_outer(o: *const Outer);
}

fn main() {
    let n = Nested { inner: 42 };
    let o = Outer { nested: Box::into_raw(Box::new(n)) };
    unsafe { process_outer(&o) }
    unsafe { drop(Box::from_raw(o.nested)) }
}
